15	import fs from 'node:fs';
16	import path from 'node:path';
17	
18	import { guild, generateId } from '@shardworks/nexus-core';
19	
20	import { git, resolveDefaultBranch, resolveRef, commitsAhead, GitError } from './git.ts';
21	
22	import type {
23	  CodexRecord,
24	  CodexDetail,
25	  DraftRecord,
