## Types

### `ScriptoriumApi`

The full `provides` interface — see [API](#api) above for usage.

### Record Types

```typescript
interface CodexRecord {
  name: string
  remoteUrl: string
  cloneStatus: 'ready' | 'cloning' | 'error'
  activeDrafts: number
}

interface CodexDetail extends CodexRecord {
  defaultBranch: string
  lastFetched: string | null
  drafts: DraftRecord[]
}

interface DraftRecord {
  id: string
  codexName: string
  branch: string
  path: string
  createdAt: string
  associatedWith?: string
}
```

### Request / Result Types

```typescript
interface OpenDraftRequest {
  codexName: string
  branch?: string
  startPoint?: string
  associatedWith?: string
}

interface AbandonDraftRequest {
  codexName: string
  branch: string
  force?: boolean
}

interface SealRequest {
  codexName: string
  sourceBranch: string
  targetBranch?: string
  maxRetries?: number
  keepDraft?: boolean
}

interface SealResult {
  success: boolean
  strategy: 'fast-forward' | 'rebase'
  retries: number
  sealedCommit: string
  /** Number of inscriptions (commits) incorporated from the draft. 0 = no-op seal. */
  inscriptionsSealed: number
}

interface PushRequest {
  codexName: string
  branch?: string
}
```

